const BOT_TOKEN = $env.TELEGRAM_BOT_TOKEN;
const FLORIST_CHAT_IDS = ['125048853', '435672235'];
const update = $('Telegram updates').item.json.body || $('Telegram updates').item.json;
const rows = $input.all().map(item => item.json);

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

async function telegram(method, body) {
  if (!BOT_TOKEN) throw new Error('TELEGRAM_BOT_TOKEN is not set');
  return await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${BOT_TOKEN}/${method}`,
    body,
    json: true,
  });
}

async function notifyAdmins(text) {
  const sent = [];
  for (const chatId of FLORIST_CHAT_IDS) {
    const result = await telegram.call(this, 'sendMessage', {
      chat_id: chatId,
      text,
      parse_mode: 'HTML',
      disable_web_page_preview: true,
    });
    sent.push({ type: 'admin', chat_id: chatId, ok: result.ok === true });
  }
  return sent;
}

const callback = update.callback_query;
const message = update.message;

if (callback?.data) {
  const [action, orderId] = String(callback.data).split(':');
  const row = rows.find(r => String(r.order_id || '').trim() === String(orderId || '').trim());

  if (!row) {
    await telegram.call(this, 'answerCallbackQuery', {
      callback_query_id: callback.id,
      text: 'Заказ не найден',
      show_alert: true,
    });
    return [{ json: { ok: false, ignored: true, reason: 'order_not_found' } }];
  }

  if (action === 'approve') {
    await telegram.call(this, 'answerCallbackQuery', {
      callback_query_id: callback.id,
      text: 'Спасибо, заказ одобрен',
    });
    await telegram.call(this, 'sendMessage', {
      chat_id: callback.message.chat.id,
      text: `✅ Заказ ${orderId} одобрен. Передаём флористу и готовим доставку.`,
    });
    const sent = await notifyAdmins([
      '✅ <b>Клиент одобрил фото букета</b>',
      '',
      `Заказ: <code>${escapeHtml(orderId)}</code>`,
      `Клиент: ${escapeHtml(row.customer_name || '-')}`,
    ].join('\n'));
    return [{ json: {
      ok: true,
      order_id: orderId,
      order_status: 'approved',
      notes: `${row.notes || ''}\napproved_at=${new Date().toISOString()}`.trim(),
      sent,
    }}];
  }

  if (action === 'revision') {
    await telegram.call(this, 'answerCallbackQuery', {
      callback_query_id: callback.id,
      text: 'Напишите, что нужно изменить',
    });
    await telegram.call(this, 'sendMessage', {
      chat_id: callback.message.chat.id,
      text: `✏️ Напишите одним сообщением, что изменить в заказе ${orderId}.`,
    });
    return [{ json: {
      ok: true,
      order_id: orderId,
      order_status: 'revision_waiting_comment',
      notes: `${row.notes || ''}\nrevision_requested_at=${new Date().toISOString()}`.trim(),
      sent: [],
    }}];
  }
}

if (message?.text) {
  const chatId = String(message.chat.id || '');
  const text = String(message.text || '').trim();
  const row = rows
    .filter(r => String(r.telegram_id || '').trim() === chatId)
    .reverse()
    .find(r => String(r.order_status || '').trim() === 'revision_waiting_comment');

  if (!row) {
    return [{ json: { ok: true, ignored: true, reason: 'no_revision_waiting_comment' } }];
  }

  await telegram.call(this, 'sendMessage', {
    chat_id: chatId,
    text: 'Спасибо, передали замечания флористу.',
  });

  const sent = await notifyAdmins([
    '✏️ <b>Клиент просит изменить букет</b>',
    '',
    `Заказ: <code>${escapeHtml(row.order_id)}</code>`,
    `Клиент: ${escapeHtml(row.customer_name || '-')}`,
    '',
    '<b>Замечания:</b>',
    escapeHtml(text),
  ].join('\n'));

  return [{ json: {
    ok: true,
    order_id: row.order_id,
    order_status: 'revision_requested',
    notes: `${row.notes || ''}\nrevision_comment=${text}\nrevision_comment_at=${new Date().toISOString()}`.trim(),
    sent,
  }}];
}

return [{ json: { ok: true, ignored: true, reason: 'unsupported_update' } }];
